 1→import { Command, END } from '@langchain/langgraph';
 2→import { createAgent, dynamicSystemPromptMiddleware } from 'langchain';
 3→import { LanguageModelLike } from '@langchain/core/language_models/base';
 4→import { SetRequired } from 'type-fest';
 5→import { askUserTool } from '../../tools/ask-user.tool';
 6→import { DEEP_RESEARCH_DISPATCH_TARGET, dispatchTool } from '../../tools/dispatch.tool';
 7→import { ENodeName, EToolName } from '../../../common/constant';
 8→import { IAskUserPayload } from '../../../common/ask-user';
 9→import { State } from '../../deep-research/state';
10→import { getToolCallResultMessage } from '../../deep-research/node/utils';
11→import { createToolErrorMiddleware } from '../../middleware/tool-error.middleware';
12→
13→export const DEEP_RESEARCH_NODE = DEEP_RESEARCH_DISPATCH_TARGET;
14→
15→const COORDINATOR_SYSTEM_PROMPT = `你是「AI 助手」，一位友好且专业的助手。
16→
17→# 职责
18→
19→- 响应问候语（如"你好"、"早上好"）和日常闲聊
20→- 礼貌拒绝不当或有害请求
21→- 需要深入研究、信息检索、复杂规划、结构化报告时，将任务派发给 deep-research
22→
23→# 可用动作
24→
25→- 当需要更多信息时，调用 ask-user 工具
26→- 当需要深入研究时，调用 dispatch 工具，并将 name 设置为 deep-research
27→- 当你已经准备好直接回复用户时，直接输出最终答案
28→
29→# 注意事项
30→
31→- 始终使用和用户相同的语言
32→- 尽可能减少 ask-user 的使用次数；如果必须提问，应一次性把当前缺失的关键信息都问完
33→- 只要你是在向用户索取缺失信息、澄清范围、确认地点/时间/对象，必须调用 ask-user 工具，绝对不要直接输出文字问题
34→- 任何带有“请问/请提供/请告诉我/你想看哪个城市/还需要补充什么”等澄清性质的话，都必须通过 ask-user 发出，不能作为普通 assistant 文本输出
35→- 如果信息不足以继续执行 deep-research，你唯一允许的动作是 ask-user；禁止先输出一段问题再结束
36→- 只有在你已经拿到足够信息、且不需要用户再补充任何内容时，才能直接输出最终答案
37→- 调用 ask-user 后，停止后续输出，等待用户回复
38→- 调用 dispatch 后，停止后续输出，由 deep-research 接管`;
39→
40→export const createCoordinatorNode = (llm: LanguageModelLike) => {
41→  const agent = createAgent({
42→    model: llm,
43→    tools: [askUserTool, dispatchTool],
44→    middleware: [createToolErrorMiddleware(), dynamicSystemPromptMiddleware(async () => COORDINATOR_SYSTEM_PROMPT)],
45→  });
46→
47→  return async (state: State): Promise<Command> => {
48→    const response = await agent.invoke({ messages: state.messages });
49→    const additional = response.messages.slice(state.messages.length);
50→    const update: SetRequired<Partial<State>, 'messages'> = { messages: additional };
51→
52→    const askUser = getToolCallResultMessage(additional, EToolName.AskUser);
53→    if (askUser?.artifact) {
54→      update.pendingInteraction = {
55→        ...(askUser.artifact as IAskUserPayload),
56→        agent: ENodeName.Coordinator,
57→        resumeNode: ENodeName.Coordinator,
58→      };
59→      return new Command({ goto: ENodeName.Interaction, update });
60→    }
61→
62→    const dispatch = getToolCallResultMessage(additional, EToolName.Dispatch);
63→    if (dispatch?.artifact) {
64→      const target = (dispatch.artifact as { name?: unknown }).name;
65→      if (target !== DEEP_RESEARCH_NODE) {
66→        throw new Error('Unknown dispatch target');
67→      }
68→      return new Command({ goto: DEEP_RESEARCH_NODE, update });
69→    }
70→
71→    return new Command({ goto: END, update });
72→  };
73→};
74→

  1→import { isHumanMessage, isToolMessage, HumanMessage } from '@langchain/core/messages';
  2→import { Command, END } from '@langchain/langgraph';
  3→import { SetRequired } from 'type-fest';
  4→import { EToolName, ENodeName } from '../../../common/constant';
  5→import { IAskUserPayload } from '../../../common/ask-user';
  6→import { log } from '../../../logger';
  7→import { State } from '../state';
  8→import { isToolCallOrResultMessage, isTextOnlyAIMessage, getToolCallResultMessage, getToolCall } from './utils';
  9→import { LanguageModelLike } from '@langchain/core/language_models/base';
 10→import { createAgent, dynamicSystemPromptMiddleware } from 'langchain';
 11→import { next, planning } from '../../tools/deep-research/internal';
 12→import { askUserTool } from '../../tools/ask-user.tool';
 13→import { ChatOpenAI } from '@langchain/openai';
 14→import { ChatAnthropic } from '@langchain/anthropic';
 15→import { render } from '../../prompts/renderer';
 16→import { createToolErrorMiddleware } from '../../middleware/tool-error.middleware';
 17→
 18→export const createPlannerNode = (llm: LanguageModelLike) => {
 19→  const deliveries = [
 20→    {
 21→      name: ENodeName.Writer,
 22→      description: '擅长基于所有收集到的信息生成清晰、结构化的 Markdown 文档报告',
 23→    },
 24→  ];
 25→
 26→  const agent = createAgent({
 27→    model: llm,
 28→    tools: [planning, next, askUserTool],
 29→    middleware: [
 30→      createToolErrorMiddleware(),
 31→      dynamicSystemPromptMiddleware(async () =>
 32→        render('deep-research/planner.md', {
 33→          currentTime: new Date().toLocaleString(),
 34→          members: [
 35→            {
 36→              name: ENodeName.Researcher,
 37→              description: '擅长使用提供的工具（包括但不限于联网搜索、链接读取、视觉理解等能力）收集信息',
 38→            },
 39→            ...deliveries,
 40→          ],
 41→          deliveries,
 42→        })
 43→      ),
 44→    ],
 45→  });
 46→
 47→  return async (state: State): Promise<Command> => {
 48→    const messages = state.messages.filter(
 49→      it =>
 50→        isToolCallOrResultMessage(it, [EToolName.Planning, EToolName.Next, EToolName.AskUser]) ||
 51→        (isTextOnlyAIMessage(it) && it.name === ENodeName.Planner) ||
 52→        isHumanMessage(it)
 53→    );
 54→
 55→    // ReactAgent 的 AgentNode 在 LLM 调用前会检查最后一条消息：
 56→    // 如果是 returnDirect 工具的 ToolMessage，则跳过 LLM 调用直接返回空消息。
 57→    // next 工具设有 returnDirect: true，在 researcher 交付后 next 的 ToolMessage
 58→    // 恰好是最后一条，导致 planner 二次调用时 LLM 被跳过，整个图直接结束。
 59→    // 追加一条消息来触发 LLM 分析任务完成状态并继续调度。
 60→    const lastMessage = messages.at(-1);
 61→    if (lastMessage && isToolMessage(lastMessage) && lastMessage.name === EToolName.Next) {
 62→      messages.push(new HumanMessage('请继续'));
 63→    }
 64→
 65→    log('planner input: ' + JSON.stringify(messages));
 66→    const response = await agent.invoke({ messages });
 67→    const additional = response.messages.slice(messages.length);
 68→    log('planner output: ' + JSON.stringify(additional));
 69→    const update: SetRequired<Partial<State>, 'messages'> = { messages: additional };
 70→
 71→    const planning = getToolCallResultMessage(additional, EToolName.Planning);
 72→    if (planning) {
 73→      log('update tasks: ' + JSON.stringify(planning.artifact));
 74→      update.tasks = planning.artifact.tasks;
 75→    }
 76→
 77→    const askUser = getToolCallResultMessage(additional, EToolName.AskUser);
 78→    if (askUser?.artifact) {
 79→      update.pendingInteraction = {
 80→        ...(askUser.artifact as IAskUserPayload),
 81→        agent: ENodeName.Planner,
 82→        resumeNode: ENodeName.Planner,
 83→      };
 84→      return new Command({ goto: ENodeName.Interaction, update });
 85→    }
 86→
 87→    const next = getToolCallResultMessage(additional, EToolName.Next);
 88→    if (next) {
 89→      if (!next.artifact) {
 90→        log(`Invalid input of tool 'next': ${JSON.stringify(getToolCall(additional, EToolName.Next))}`);
 91→        throw new Error('任务调度异常');
 92→      }
 93→
 94→      update.currentTaskIndex = next.artifact.index;
 95→
 96→      let tasks = update.tasks || state.tasks;
 97→      if (next.artifact.update) {
 98→        tasks = tasks.map((task, index) =>
 99→          index === next.artifact.index ? { ...task, ...next.artifact.update } : task
100→        );
101→        update.tasks = tasks;
102→      }
103→
104→      if (tasks[next.artifact.index].handler == ENodeName.Writer) {
105→        let modelName = '未知模型';
106→        if (llm instanceof ChatOpenAI) {
107→          modelName = llm.model;
108→        } else if (llm instanceof ChatAnthropic) {
109→          modelName = llm.model || '未知模型';
110→        }
111→        log(`规划最终文档输出: ${modelName}`);
112→      }
113→
114→      return new Command({ goto: tasks[next.artifact.index].handler || END, update });
115→    }
116→
117→    return new Command({ goto: END, update });
118→  };
119→};
120→

  1→import { HumanMessage, ToolMessage, BaseMessage, isToolMessage } from '@langchain/core/messages';
  2→import { Command, GraphRecursionError } from '@langchain/langgraph';
  3→import { Except } from 'type-fest';
  4→import { ReusableTools, ENodeName, EToolName, ETaskStatus, TaskStatusText } from '../../../common/constant';
  5→import { log } from '../../../logger';
  6→import { ITaskResult, MessagesReducer, State } from '../state';
  7→import { getToolCallAndResultMessages, getLatestAITextContent, getToolCallResultMessage, getToolCall } from './utils';
  8→import { LanguageModelLike } from '@langchain/core/language_models/base';
  9→import { createAgent, dynamicSystemPromptMiddleware } from 'langchain';
 10→import {
 11→  getGeolocation,
 12→  getNavigation,
 13→  getTrainRoute,
 14→  searchPoiByType,
 15→  searchPoiByName,
 16→  searchPoiByLocation,
 17→  getWeather,
 18→} from '../../tools/deep-research/amap';
 19→import { tavily } from '../../tools/deep-research/search';
 20→import { deliver } from '../../tools/deep-research/internal';
 21→import { getPromptDocumentPath, render } from '../../prompts/renderer';
 22→import { readFile } from 'fs/promises';
 23→import { createToolErrorMiddleware } from '../../middleware/tool-error.middleware';
 24→
 25→export const createResearcherNode = (llm: LanguageModelLike) => {
 26→  const agent = createAgent({
 27→    model: llm,
 28→    tools: [
 29→      tavily,
 30→      getWeather,
 31→      getGeolocation,
 32→      getNavigation,
 33→      getTrainRoute,
 34→      searchPoiByType,
 35→      searchPoiByName,
 36→      searchPoiByLocation,
 37→      deliver,
 38→    ],
 39→    middleware: [
 40→      createToolErrorMiddleware(),
 41→      dynamicSystemPromptMiddleware(async () =>
 42→        render('deep-research/researcher.md', {
 43→          currentTime: new Date().toLocaleString(),
 44→          poiCodeList: await readFile(getPromptDocumentPath('deep-research/poi-code.json'), {
 45→            encoding: 'utf-8',
 46→          }),
 47→          regionCodeList: await readFile(getPromptDocumentPath('deep-research/region-code.txt'), {
 48→            encoding: 'utf-8',
 49→          }),
 50→        })
 51→      ),
 52→    ],
 53→  });
 54→
 55→  return async (state: State): Promise<Command> => {
 56→    const task = state.tasks[state.currentTaskIndex];
 57→    const messages = [
 58→      ...getToolCallAndResultMessages(state.messages, ReusableTools),
 59→      new HumanMessage(`任务标题：${task.title}\n任务描述：${task.description}`),
 60→    ];
 61→    log(`researcher input: ${JSON.stringify(messages)}`);
 62→    const response = await agent.invoke({ messages }, { recursionLimit: 75 }).catch(error => {
 63→      if (error instanceof GraphRecursionError) {
 64→        log('researcher recursion exceeded');
 65→        return {
 66→          messages: messages.concat(
 67→            new ToolMessage({
 68→              name: EToolName.Deliver,
 69→              tool_call_id: '',
 70→              content: '',
 71→              artifact: {
 72→                status: ETaskStatus.Failed,
 73→                message: '经过多次尝试，无法收集到足够信息',
 74→              } satisfies ITaskResult,
 75→            })
 76→          ) as BaseMessage[],
 77→        };
 78→      }
 79→
 80→      throw error;
 81→    });
 82→    const additional = response.messages.slice(messages.length);
 83→    log(`researcher output: ${JSON.stringify(additional)}`);
 84→
 85→    const messagesNew: BaseMessage[] = getToolCallAndResultMessages(additional, ReusableTools);
 86→    const update: Partial<Except<State, 'messages'>> & { messages?: MessagesReducer } = {};
 87→
 88→    const result: ITaskResult =
 89→      (getToolCallResultMessage(additional, EToolName.Deliver)?.artifact as ITaskResult | undefined) ||
 90→      ({
 91→        status: ETaskStatus.Failed,
 92→        message: (getLatestAITextContent(additional) || '') as string,
 93→      } satisfies ITaskResult);
 94→
 95→    const next = getToolCall(state.messages, EToolName.Next);
 96→    if (next) {
 97→      update.messages = current =>
 98→        current
 99→          .map(it =>
100→            isToolMessage(it) && it.name === EToolName.Next && it.tool_call_id === next.id
101→              ? new ToolMessage({
102→                  tool_call_id: next.id!,
103→                  name: EToolName.Next,
104→                  content: `任务状态：${TaskStatusText[result.status]}\n详情：${result.message}`,
105→                })
106→              : it
107→          )
108→          .concat(...messagesNew);
109→    } else {
110→      update.messages = messagesNew;
111→    }
112→
113→    return new Command({ goto: ENodeName.Planner, update });
114→  };
115→};
116→

 1→import { AIMessage, BaseMessage, HumanMessage, isAIMessage, isHumanMessage } from '@langchain/core/messages';
 2→import { Command, END } from '@langchain/langgraph';
 3→import { ENodeName, ReusableTools } from '../../../common/constant';
 4→import { log } from '../../../logger';
 5→import { State } from '../state';
 6→import { getAITextContent, isToolCallOrResultMessage } from './utils';
 7→import { LanguageModelLike } from '@langchain/core/language_models/base';
 8→import { createAgent, dynamicSystemPromptMiddleware } from 'langchain';
