11→const MAX_WRITER_CONTINUATIONS = 3;
12→
13→function getLastAIMessage(messages: BaseMessage[]): AIMessage | undefined {
14→  return [...messages].reverse().find((message): message is AIMessage => isAIMessage(message));
15→}
16→
17→function isLengthTruncated(message: AIMessage | undefined): boolean {
18→  if (!message) {
19→    return false;
20→  }
21→
22→  const metadata = message as unknown as {
23→    response_metadata?: Record<string, unknown>;
24→    responseMetadata?: Record<string, unknown>;
25→  };
26→  const responseMetadata = metadata.response_metadata || metadata.responseMetadata || {};
27→  const finishReason = responseMetadata.finish_reason || responseMetadata.finishReason;
28→  const stopReason = responseMetadata.stop_reason || responseMetadata.stopReason;
29→
30→  return (
31→    finishReason === 'length' ||
32→    finishReason === 'max_tokens' ||
33→    stopReason === 'max_tokens' ||
34→    stopReason === 'model_length'
35→  );
36→}
