222→  // 返回对应conversation_id的savor
223→  // savor的作用是，通过队列保存chunk，在chunk id一样时覆写，并且构造链表
224→  // 在conversation中保存head和tail，head为了获取整个链表，tail为了继续写入新的链表节点
225→  private async createEventsSaver(id: string) {
226→    const enqueue = this.createQueuedExecutor();
227→    const conversation = await this.conversationModel.findOne({ id });
228→    // 获取对话的最后一个节点的内容
229→    let buffer: ILinkedEvent | null | undefined = conversation?.tail
230→      ? await this.events.getTail(id, conversation.tail)
231→      : null;
232→
233→    return async (chunk?: ILinkedEvent) => {
234→      // 保存后续传入的内容
235→      if (buffer) {
236→        const diff = chunk?.id !== buffer.id;
237→
238→        if (diff) {
239→          // 指向下一个节点
240→          buffer.next_id = chunk?.id;
241→        }
242→
243→        // 保存引用，用在闭包里，避免后面改写引用导致存入的内容丢失
244→        const snapshot = buffer;
245→        // 串行写入。流式事件可能很密集，直接并发 events.set 可能导致顺序错乱或覆盖。队列保证一次只处理一个任务。
246→        enqueue({
247→          key: buffer.id,
248→          func: retry(() => this.events.set(id, snapshot), { interval: 300 }),
249→        });
250→
251→        if (diff) {
252→          const partial: Partial<Conversation> = { tail: buffer.id };
253→          if (buffer.node && TalkableAgents.includes(buffer.node)) {
254→            partial.node = buffer.node;
255→          }
256→          await this.conversationModel.updateOne({ id }, partial);
257→          buffer = chunk;
258→        }
259→      } else if (chunk) {
260→        buffer = chunk;
261→        // 仅在对话没有 head 时才记录（避免因 Redis 丢失 tail 数据时覆盖已有的历史链）
262→        if (!conversation?.head) {
263→          await this.conversationModel.updateOne({ id }, { head: chunk.id });
264→        }
265→      }
266→    };
267→  }
268→
269→  // 队列写入
270→  private createQueuedExecutor() {
271→    interface IAction {
272→      key: string;
273→      func: () => Promise<void>;
274→    }
275→
276→    const queue: IAction[] = [];
277→    let loading = false;
278→
279→    const dequeue = () => {
280→      loading = true;
281→      const action = queue.shift();
282→      if (action) {
283→        // 递归调用出队，确保每个任务都能被执行
284→        action.func().finally(dequeue);
285→      } else {
286→        loading = false;
287→      }
288→    };
289→
290→    const enqueue = (action: IAction) => {
291→      // 如果队列中有对应的任务，则替换func为新的func
292→      const existed = queue.find(it => it.key === action.key);
293→      if (existed) {
294→        existed.func = action.func;
295→        return;
296→      }
297→      // 如果没有任务，则直接加入队列
298→      queue.push(action);
299→      // 如果不处在loading态（没有进行中的任务，则开始出队）
300→      if (!loading) {
301→        dequeue();
302→      }
303→    };
304→
305→    return enqueue;
306→  }
307→
308→  // 分片聚合，如果是一连串同类型的chunk，则id始终都是这串的第一个chunk的id，但是内容一直拼接。
309→  private createChunkAggregator() {
310→    // 上一个事件
311→    let latest: IGraphEvent | undefined;
312→    const concat = (a: string | undefined | null, b: string | undefined | null) => (a && b ? a + b : a || b);
313→    const getSourceKey = (event?: IGraphEvent) => event?.subagent_namespace || 'main';
314→
315→    return (chunk: IGraphEvent) => {
316→      // 连续 assistant 分片同节点则合并 thinking 与 content ，避免存储碎片过多
317→      if (
318→        chunk.event === 'assistant' &&
319→        latest?.event === 'assistant' &&
320→        chunk.node === latest.node &&
321→        getSourceKey(chunk) === getSourceKey(latest)
322→      ) {
323→        // @ts-expect-error: type todo
324→        latest.data.thinking = concat(latest.data.thinking, chunk.data.thinking);
325→        // @ts-expect-error: type todo
326→        latest.data.content = concat(latest.data.content, chunk.data.content);
327→        return latest;
328→      }
329→
330→      // 连续 tool-input 同工具名则拼接输入文本
331→      if (
332→        chunk.event === 'tool-input' &&
333→        latest?.event === 'tool-input' &&
334→        getSourceKey(chunk) === getSourceKey(latest) &&
335→        // @ts-expect-error: type todo
336→        chunk.data.name === latest.data.name
337→      ) {
338→        // @ts-expect-error: type todo
339→        latest.data.input = latest.data.input + chunk.data.input;
340→        return latest;
341→      }
342→
343→      latest = chunk;
344→      return chunk;
345→    };
346→  }
347→
348→  private async pipe(
349→    id: string,
350→    generator: AsyncGenerator<IGraphEvent>,
351→    response: PassThrough,
352→    ac: AbortController,
353→    save: (chunk?: ILinkedEvent) => Promise<void>,
354→  ) {
355→    const aggregate = this.createChunkAggregator();
356→    const send = async (chunk: ILinkedEvent) => {
357→      const tokenUsage = this.extractTokenUsageFromAssistantEnd(chunk);
358→      if (tokenUsage) {
359→        await this.conversationModel.updateOne({ id }, { tokenUsage });
360→      }
361→
362→      // 这里在保存的时候，会因为aggregate的累加机制，使得id不变，但是内容不断累加
363→      await save(aggregate(chunk as IGraphEvent));
364→
365→      if (!response.destroyed) {
366→        const payload = this.toClientEvent(chunk as unknown as Record<string, unknown>);
367→        return new Promise<void>((resolve, reject) =>
368→          response.write(`${JSON.stringify(payload)}\n`, error => {
369→            if (error) {
370→              reject(error);
371→            } else {
372→              resolve();
373→            }
374→          }),
375→        );
376→      }
377→    };
378→
379→    const writeKeepAlive = () => {
380→      if (!response.destroyed) {
381→        response.write('\n');
382→      }
383→    };
384→
385→    try {
386→      await this.conversation.start(id);
387→
388→      const keepAliveInterval = setInterval(writeKeepAlive, 15_000);
389→      try {
390→        for await (const chunk of generator) {
391→          await this.checkAborted(id, ac);
392→          await send(chunk);
393→        }
394→      } finally {
395→        clearInterval(keepAliveInterval);
396→      }
397→      await send({ id: randomUUID(), event: 'end', timestamp: Date.now() });
398→    } catch (error) {
399→      const message = formatError(error);
400→      this.logger.error({ conversationId: id, error, message }, 'Chat stream failed');
401→      await send({ id: randomUUID(), event: 'error', data: message, timestamp: Date.now() });
402→    } finally {
403→      save();
404→      response.end();
405→      await this.conversation.stop(id);
406→    }
407→  }
408→
409→  private async checkAborted(id: string, ac: AbortController) {
410→    const generating = await this.conversation.isGenerating(id);
411→    if (generating) {
412→      await this.conversation.chunk(id);
413→    } else {
414→      ac.abort();
415→      // compatible with abort error message of langgraph
416→      throw new Error('Aborted');
417→    }
418→  }
419→
420→  private enableStream(request: Request, response: Response) {
421→    request.socket.setTimeout(0);
422→    request.socket.setNoDelay();
423→    request.socket.setKeepAlive(true);
424→    response.setHeader('content-type', 'text/plain; charset=utf-8');
425→    response.setHeader('cache-control', 'no-cache');
426→    response.setHeader('connection', 'keep-alive');
427→  }
428→}
