279→export function handleChatModelStream(
280→  data: { chunk: unknown },
281→  node: ENodeName | undefined,
282→  state: ToolInputState,
283→  subagent?: StreamSubagentInfo,
284→): IGraphEvent | undefined {
285→  // eslint-disable-next-line @typescript-eslint/no-explicit-any
286→  if (!data.chunk || !isAIMessageChunk(data.chunk as any)) return undefined;
287→
288→  const chunk = data.chunk as AIMessageChunk;
289→  const { tool_call_chunks } = chunk;
290→  const { text, thinking, tool } = parseChunk(chunk);
291→
292→  if (tool) {
293→    state.inputtingTool = tool;
294→    return createToolInputEvent(tool, tool_call_chunks, node, subagent);
295→  }
296→
297→  if (state.inputtingTool && tool_call_chunks?.length) {
298→    return createToolInputEvent(state.inputtingTool, tool_call_chunks, node, subagent);
299→  }
300→
301→  if (text || thinking) {
302→    return makeEvent('assistant', node, { thinking, content: text }, subagent);
303→  }
304→
305→  return undefined;
306→}
