413→export function handleToolError(
414→  runId: string,
415→  name: string,
416→  data: { error?: unknown },
417→  node: ENodeName | undefined,
418→  subagent?: StreamSubagentInfo,
419→): IGraphEvent | undefined {
420→  if (name === EToolName.AskUser) {
421→    return undefined;
422→  }
423→
424→  const message = extractToolError(data.error) ?? tryJSONStringify(data.error) ?? 'Tool execution failed';
425→  log(`tool-call-result(${name}).error: ${message}`);
426→  const summarizedMessage = shouldSummarizeToolCallResult(name)
427→    ? summarizeToolCallResult(message)
428→    : message;
429→
430→  return makeEvent('tool-call-result', node, {
431→    id: runId,
432→    name,
433→    outputLength: message.length,
434→    error: summarizedMessage,
